import{_ as e,o as l,c as d,a3 as a}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"Composables 概览","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/composables-overview.md","filePath":"architecture/composables-overview.md","lastUpdated":1769749478000}'),o={name:"architecture/composables-overview.md"};function s(r,t,n,i,c,g){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="composables-概览" tabindex="-1">Composables 概览 <a class="header-anchor" href="#composables-概览" aria-label="Permalink to &quot;Composables 概览&quot;">​</a></h1><p>本文档提供了 <code>src/composables</code> 目录下所有可复用逻辑模块的索引和简要说明。</p><h2 id="_1-窗口同步与管理" tabindex="-1">1. 窗口同步与管理 <a class="header-anchor" href="#_1-窗口同步与管理" aria-label="Permalink to &quot;1. 窗口同步与管理&quot;">​</a></h2><p>核心的多窗口架构实现。</p><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useWindowSyncBus</code></td><td style="text-align:left;"><strong>核心</strong>。基于事件总线的跨窗口通信机制（握手、心跳、消息广播）。</td></tr><tr><td style="text-align:left;"><code>useDetachable</code></td><td style="text-align:left;">实现拖拽分离交互逻辑（拖拽阈值检测、rdev 会话管理）。</td></tr><tr><td style="text-align:left;"><code>useDetachedManager</code></td><td style="text-align:left;">管理所有分离窗口的生命周期（创建、关闭、位置调整）。</td></tr><tr><td style="text-align:left;"><code>useStateSyncEngine</code></td><td style="text-align:left;"><strong>核心状态同步引擎</strong>。封装了自动推送/接收、<strong>增量更新 (Delta Sync)</strong> 和全局状态源注册中心，用于在多窗口间高效同步任意响应式状态 (<code>Ref</code>)。</td></tr><tr><td style="text-align:left;"><code>useWindowResize</code></td><td style="text-align:left;">监听窗口大小变化，提供响应式尺寸数据。</td></tr></tbody></table><h2 id="_2-主题与-ui" tabindex="-1">2. 主题与 UI <a class="header-anchor" href="#_2-主题与-ui" aria-label="Permalink to &quot;2. 主题与 UI&quot;">​</a></h2><p>外观定制与响应式主题。</p><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useTheme</code></td><td style="text-align:left;">管理全局主题模式（Auto/Light/Dark）及切换逻辑。</td></tr><tr><td style="text-align:left;"><code>useThemeAppearance</code></td><td style="text-align:left;"><strong>核心</strong>。管理动态主题外观（窗口特效、UI透明/模糊、壁纸轮播、颜色混合与提取）。</td></tr><tr><td style="text-align:left;"><code>useThemeAwareIcon</code></td><td style="text-align:left;">智能处理 SVG 图标，将黑白颜色替换为 <code>currentColor</code> 以自适应主题。</td></tr><tr><td style="text-align:left;"><code>useIframeTheme</code></td><td style="text-align:left;">向 iframe 注入当前主题 CSS 变量及基础样式适配，确保视觉一致性。</td></tr><tr><td style="text-align:left;"><code>useCssOverrides</code></td><td style="text-align:left;">管理用户自定义 CSS 覆盖，支持预设管理、实时预览和动态注入。</td></tr></tbody></table><h2 id="_3-llm-与-ai-能力" tabindex="-1">3. LLM 与 AI 能力 <a class="header-anchor" href="#_3-llm-与-ai-能力" aria-label="Permalink to &quot;3. LLM 与 AI 能力&quot;">​</a></h2><p>AI 模型配置与请求处理。</p><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useLlmProfiles</code></td><td style="text-align:left;">管理 LLM 服务商配置（API Key 数组、Base URL、模型列表），支持 localStorage 迁移、参数能力查询及预设模板创建。</td></tr><tr><td style="text-align:left;"><code>useLlmRequest</code></td><td style="text-align:left;"><strong>核心请求中间件</strong>。封装多提供商 LLM 请求，支持多模态输入与双流并行（Content/Reasoning），智能过滤参数（基于 Provider 和 Model 能力），处理 AbortError。</td></tr><tr><td style="text-align:left;"><code>useLlmKeyManager</code></td><td style="text-align:left;"><strong>密钥调度中心</strong>。管理多 API Key 的轮询、健康检测、成功率反馈及自动熔断机制。</td></tr><tr><td style="text-align:left;"><code>useModelMetadata</code></td><td style="text-align:left;"><strong>通用元数据系统</strong>。基于规则管理模型元数据（图标、分组、能力、上下文限制），支持模糊/精确/正则匹配，提供三级优先级图标解析（模型自定义 &gt; 规则匹配 &gt; fallback）。</td></tr><tr><td style="text-align:left;"><code>useModelSelectDialog</code></td><td style="text-align:left;">全局模型选择对话框，基于 Promise 的异步选择机制，返回 <code>{ profile, model }</code> 或 <code>null</code>。</td></tr><tr><td style="text-align:left;"><code>useAgentPresets</code></td><td style="text-align:left;">从 <code>config/agent-presets/</code> 自动加载 Agent 预设（JSON/YAML），支持按标签/分类查询。</td></tr><tr><td style="text-align:left;"><code>useOcrProfiles</code></td><td style="text-align:left;">管理 OCR 服务配置，支持 localStorage 迁移、并发控制和延迟参数。</td></tr></tbody></table><h2 id="_4-文件与资源管理" tabindex="-1">4. 文件与资源管理 <a class="header-anchor" href="#_4-文件与资源管理" aria-label="Permalink to &quot;4. 文件与资源管理&quot;">​</a></h2><p>文件操作与预览。</p><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useAssetManager</code></td><td style="text-align:left;"><strong>核心</strong>。提供资产全生命周期管理（导入、查询、删除），并处理与后端存储的交互和路径转换。</td></tr><tr><td style="text-align:left;"><code>useFileInteraction</code></td><td style="text-align:left;">统一处理文件拖放和粘贴交互，支持文件、路径或 Asset 多种处理模式。</td></tr><tr><td style="text-align:left;"><code>useFileDrop</code></td><td style="text-align:left;">监听 Tauri 拖放事件，捕获文件系统路径并提供验证和状态反馈。</td></tr><tr><td style="text-align:left;"><code>useAttachmentProcessor</code></td><td style="text-align:left;">扫描文本，将内联 Base64 数据（如粘贴的图片）智能转换为 Asset 文件。</td></tr><tr><td style="text-align:left;"><code>useDocumentViewer</code></td><td style="text-align:left;">提供文档预览核心逻辑，支持 Markdown/HTML/代码预览，源码与渲染模式切换。</td></tr><tr><td style="text-align:left;"><code>useImageViewer</code></td><td style="text-align:left;">提供全局图片预览服务，自动处理 <code>appdata://</code> 等本地路径为可显示 URL。</td></tr><tr><td style="text-align:left;"><code>useVideoViewer</code></td><td style="text-align:left;">提供全局视频预览服务，支持 <code>Asset</code> 对象和多种路径格式。</td></tr><tr><td style="text-align:left;"><code>useAudioViewer</code></td><td style="text-align:left;">提供全局音频预览服务，支持可视化频谱显示与 Asset 路径转换。</td></tr></tbody></table><h2 id="_5-设置与配置" tabindex="-1">5. 设置与配置 <a class="header-anchor" href="#_5-设置与配置" aria-label="Permalink to &quot;5. 设置与配置&quot;">​</a></h2><p>应用级配置管理。</p><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useSettingsNavigator</code></td><td style="text-align:left;">跨窗口设置导航（主窗口直接跳转，分离窗口通过 Tauri 命令聚焦主窗口并导航）。</td></tr><tr><td style="text-align:left;"><code>useLogConfig</code></td><td style="text-align:left;">管理日志系统配置（级别、文件/控制台输出、缓冲区大小），响应式监听设置变化并自动应用。</td></tr></tbody></table><h2 id="_6-消息与通知" tabindex="-1">6. 消息与通知 <a class="header-anchor" href="#_6-消息与通知" aria-label="Permalink to &quot;6. 消息与通知&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Composable</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>useNotification</code></td><td style="text-align:left;"><strong>核心通知系统</strong>。提供统一的消息推送接口（success/error/info），支持持久化存储、已读管理、路由跳转及来源追踪。</td></tr><tr><td style="text-align:left;"><code>useSendToChat</code></td><td style="text-align:left;">提供统一的&quot;发送到聊天&quot;接口，支持多种格式（纯文本/代码块/引用）、位置控制（追加/前置）、便捷方法（<code>sendCodeToChat</code>/<code>sendQuoteToChat</code>）。</td></tr></tbody></table><h2 id="开发建议" tabindex="-1">开发建议 <a class="header-anchor" href="#开发建议" aria-label="Permalink to &quot;开发建议&quot;">​</a></h2><ul><li><strong>优先复用</strong>: 在编写新功能前，请先查阅此列表，避免重复造轮子。</li><li><strong>单一职责</strong>: 新增 Composable 时，应保持功能单一，便于测试和复用。</li><li><strong>命名规范</strong>: 始终以 <code>use</code> 开头，采用驼峰命名法。</li></ul>',21)])])}const y=e(o,[["render",s]]);export{h as __pageData,y as default};
